mapper.update:
UPDATE review
SET rating  = #{rating},
    content = #{content},
    spoiler = #{spoiler}
WHERE review_no = #{reviewNo}
  AND user_no   = #{userNo}

mapper.delete:
DELETE FROM review
WHERE review_no = #{reviewNo}
  AND user_no   = #{userNo}

DELETE FROM review_like
WHERE user_no   = #{userNo}
  AND review_no = #{reviewNo}

mapper.select:
SELECT COUNT(*) FROM review_like
WHERE user_no   = #{userNo}
  AND review_no = #{reviewNo}

mapper.update:
UPDATE review
SET like_cnt = (
    SELECT COUNT(*) FROM review_like
    WHERE review_no = #{reviewNo}
)
WHERE review_no = #{reviewNo}
